CREATE OR REPLACE FUNCTION public.dump_full_schema() RETURNS text LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_catalog AS $fn$ DECLARE out_sql text := ''; r record; col_defs text; BEGIN out_sql := out_sql || E'-- =====================================================\n' || E'-- OptiGestion Migration\n' || E'-- =====================================================\n\n' || E'CREATE EXTENSION IF NOT EXISTS pgcrypto;\n\n' || E'BEGIN;\n\n'; out_sql := out_sql || E'-- ---------- TABLES ----------\n'; FOR r IN SELECT c.oid, c.relname FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace WHERE n.nspname = 'public' AND c.relkind = 'r' ORDER BY c.relname LOOP SELECT string_agg('  ' || quote_ident(a.attname) || ' ' || pg_catalog.format_type(a.atttypid, a.atttypmod) || COALESCE(' DEFAULT ' || pg_get_expr(ad.adbin, ad.adrelid), '') || CASE WHEN a.attnotnull THEN ' NOT NULL' ELSE '' END, E',\n' ORDER BY a.attnum) INTO col_defs FROM pg_attribute a LEFT JOIN pg_attrdef ad ON ad.adrelid = a.attrelid AND ad.adnum = a.attnum WHERE a.attrelid = r.oid AND a.attnum > 0 AND NOT a.attisdropped; out_sql := out_sql || format(E'CREATE TABLE IF NOT EXISTS public.%I (\n%s\n);\n\n', r.relname, col_defs); END LOOP; out_sql := out_sql || E'COMMIT;\n\n'; RETURN out_sql; END; $fn$; GRANT EXECUTE ON FUNCTION public.dump_full_schema() TO authenticated, service_role;